import { useEffect, useState } from "react";

const SIZE = 10;

const EMPTY = 0;
const SNAKE = 1;
const FOOD = 2;

function randomFood(snake) {
  while (true) {
    const row = Math.floor(Math.random() * SIZE);
    const col = Math.floor(Math.random() * SIZE);

    if (!snake.some(([r, c]) => r === row && c === col)) {
      return [row, col];
    }
  }
}

function move(game) {
  const {
    snake,
    food,
    direction,
  } = game;

  const [row, col] = snake[0];

  const head = [
    row + direction[0],
    col + direction[1],
  ];

  if (
    head[0] < 0 ||
    head[0] >= SIZE ||
    head[1] < 0 ||
    head[1] >= SIZE
  ) {
    return game;
  }

  const nextSnake = [
    head,
    ...snake,
  ];

  let nextFood = food;

  if (
    head[0] === food[0] &&
    head[1] === food[1]
  ) {
    nextFood = randomFood(nextSnake);
  } else {
    nextSnake.pop();
  }

  return {
    snake: nextSnake,
    food: nextFood,
    direction,
  };
}

function createBoard(game) {
  const board = Array.from(
    { length: SIZE },
    () => Array(SIZE).fill(EMPTY)
  );

  for (const [r, c] of game.snake) {
    board[r][c] = SNAKE;
  }

  board[game.food[0]][game.food[1]] = FOOD;

  return board;
}

export default function Snake() {
  const [game, setGame] = useState({
    snake: [[5, 5]],
    food: [2, 2],
    direction: [0, 1],
  });

  useEffect(() => {
    function keyDown(e) {
      if (e.key === "ArrowUp") {
        setGame(game => ({
          ...game,
          direction: [-1, 0],
        }));
      }

      if (e.key === "ArrowDown") {
        setGame(game => ({
          ...game,
          direction: [1, 0],
        }));
      }

      if (e.key === "ArrowLeft") {
        setGame(game => ({
          ...game,
          direction: [0, -1],
        }));
      }

      if (e.key === "ArrowRight") {
        setGame(game => ({
          ...game,
          direction: [0, 1],
        }));
      }
    }

    window.addEventListener("keydown", keyDown);

    return () => {
      window.removeEventListener("keydown", keyDown);
    };
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setGame(game => move(game));
    }, 300);

    return () => clearInterval(timer);
  }, []);

  const board = createBoard(game);

  return (
    <main>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  style={{
                    width: "2rem",
                    height: "2rem",
                    border: "1px solid",
                    padding: 0,
                    background:
                      cell === SNAKE
                        ? "green"
                        : cell === FOOD
                        ? "red"
                        : "white",
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
